// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title PokerHandVerifier
 * @notice On-chain commitment/reveal storage for provably fair poker hands
 * @dev Commitment stored after deal, reveal at showdown. Anyone can verify.
 */
contract PokerHandVerifier is Ownable {
    struct HandCommitment {
        bytes32 commitmentHash;
        uint256 vrfRequestId;
        uint256 commitTimestamp;
        bool committed;
    }

    struct HandReveal {
        string serverSeed;
        string[] playerSeeds;
        string deckOrder;
        uint256 revealTimestamp;
        bool revealed;
    }

    // tableId hash + handNumber => commitment/reveal
    mapping(bytes32 => HandCommitment) public commitments;
    mapping(bytes32 => HandReveal) private reveals;

    // Events
    event HandCommitted(
        string indexed tableId,
        uint256 indexed handNumber,
        bytes32 commitmentHash,
        uint256 vrfRequestId
    );

    event HandRevealed(
        string indexed tableId,
        uint256 indexed handNumber
    );

    constructor() Ownable(msg.sender) {}

    /**
     * @notice Commit to a hand's shuffle (called after deal, before showdown)
     */
    function commitHand(
        string calldata tableId,
        uint256 handNumber,
        bytes32 commitmentHash,
        uint256 vrfRequestId
    ) external onlyOwner {
        bytes32 key = _handKey(tableId, handNumber);
        require(!commitments[key].committed, "Already committed");

        commitments[key] = HandCommitment({
            commitmentHash: commitmentHash,
            vrfRequestId: vrfRequestId,
            commitTimestamp: block.timestamp,
            committed: true
        });

        emit HandCommitted(tableId, handNumber, commitmentHash, vrfRequestId);
    }

    /**
     * @notice Reveal hand data (called at showdown)
     */
    function revealHand(
        string calldata tableId,
        uint256 handNumber,
        string calldata serverSeed,
        string[] calldata playerSeeds,
        string calldata deckOrder
    ) external onlyOwner {
        bytes32 key = _handKey(tableId, handNumber);
        require(commitments[key].committed, "Not committed");
        require(!reveals[key].revealed, "Already revealed");

        reveals[key] = HandReveal({
            serverSeed: serverSeed,
            playerSeeds: playerSeeds,
            deckOrder: deckOrder,
            revealTimestamp: block.timestamp,
            revealed: true
        });

        emit HandRevealed(tableId, handNumber);
    }

    /**
     * @notice Verify a hand — anyone can call this
     * @return committed Whether the hand was committed
     * @return revealed Whether the hand was revealed
     * @return commitHash The commitment hash
     * @return timestamp The commit timestamp
     */
    function verifyHand(
        string calldata tableId,
        uint256 handNumber
    ) external view returns (
        bool committed,
        bool revealed,
        bytes32 commitHash,
        uint256 timestamp
    ) {
        bytes32 key = _handKey(tableId, handNumber);
        HandCommitment storage c = commitments[key];
        HandReveal storage r = reveals[key];
        return (c.committed, r.revealed, c.commitmentHash, c.commitTimestamp);
    }

    /**
     * @notice Get full hand data — anyone can call this
     */
    function getHandData(
        string calldata tableId,
        uint256 handNumber
    ) external view returns (
        string memory serverSeed,
        string[] memory playerSeeds,
        string memory deckOrder,
        bytes32 commitHash,
        uint256 vrfRequestId,
        uint256 commitTimestamp,
        uint256 revealTimestamp
    ) {
        bytes32 key = _handKey(tableId, handNumber);
        HandCommitment storage c = commitments[key];
        HandReveal storage r = reveals[key];
        return (
            r.serverSeed,
            r.playerSeeds,
            r.deckOrder,
            c.commitmentHash,
            c.vrfRequestId,
            c.commitTimestamp,
            r.revealTimestamp
        );
    }

    function _handKey(string calldata tableId, uint256 handNumber) internal pure returns (bytes32) {
        return keccak256(abi.encodePacked(tableId, handNumber));
    }
}

contracts/PokerNFTMarketplace.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title PokerNFTMarketplace
 * @notice ERC-721 NFT marketplace for poker avatars and cosmetics
 * @dev Minting, listing, buying with platform fee (2.9% standard, 2.0% for Platinum)
 */
contract PokerNFTMarketplace is ERC721, ERC721URIStorage, Ownable {
    uint256 private _nextTokenId;

    // Platform fee in basis points (290 = 2.9%, 200 = 2.0%)
    uint256 public defaultFeeBps = 290;

    struct Listing {
        address seller;
        uint256 price;
        bool active;
    }

    // tokenId => Listing
    mapping(uint256 => Listing) public listings;

    // Total fees collected (withdrawable by owner)
    uint256 public collectedFees;

    event AvatarMinted(uint256 indexed tokenId, address indexed to, string tokenURI);
    event Listed(uint256 indexed tokenId, address indexed seller, uint256 price);
    event Delisted(uint256 indexed tokenId);
    event Sold(uint256 indexed tokenId, address indexed buyer, address indexed seller, uint256 price, uint256 fee);

    constructor() ERC721("PokerAvatar", "PKAR") Ownable(msg.sender) {}

    /**
     * @notice Mint a new avatar NFT
     * @param to Address to mint to
     * @param uri IPFS URI for metadata
     */
    function mintAvatar(address to, string calldata uri) external onlyOwner returns (uint256) {
        uint256 tokenId = _nextTokenId++;
        _safeMint(to, tokenId);
        _setTokenURI(tokenId, uri);
        emit AvatarMinted(tokenId, to, uri);
        return tokenId;
    }

    /**
     * @notice List an NFT for sale
     * @param tokenId Token to list
     * @param price Price in wei (MATIC)
     */
    function listForSale(uint256 tokenId, uint256 price) external {
        require(ownerOf(tokenId) == msg.sender, "Not the owner");
        require(price > 0, "Price must be > 0");
        require(!listings[tokenId].active, "Already listed");

        // Transfer NFT to marketplace contract for escrow
        transferFrom(msg.sender, address(this), tokenId);

        listings[tokenId] = Listing({
            seller: msg.sender,
            price: price,
            active: true
        });

        emit Listed(tokenId, msg.sender, price);
    }

    /**
     * @notice Buy a listed NFT
     * @param tokenId Token to buy
     * @param feeBps Fee in basis points (server passes 290 or 200 based on buyer tier)
     */
    function buyNFT(uint256 tokenId, uint256 feeBps) external payable {
        Listing storage listing = listings[tokenId];
        require(listing.active, "Not listed");
        require(msg.value >= listing.price, "Insufficient payment");
        require(msg.sender != listing.seller, "Cannot buy own listing");

        // Calculate fee
        uint256 fee = (listing.price * feeBps) / 10000;
        uint256 sellerPayout = listing.price - fee;

        listing.active = false;
        collectedFees += fee;

        // Transfer NFT to buyer
        _transfer(address(this), msg.sender, tokenId);

        // Pay seller
        payable(listing.seller).transfer(sellerPayout);

        // Refund excess payment
        if (msg.value > listing.price) {
            payable(msg.sender).transfer(msg.value - listing.price);
        }

        emit Sold(tokenId, msg.sender, listing.seller, listing.price, fee);
    }

    /**
     * @notice Cancel a listing (seller only)
     */
    function cancelListing(uint256 tokenId) external {
        Listing storage listing = listings[tokenId];
        require(listing.active, "Not listed");
        require(listing.seller == msg.sender, "Not the seller");

        listing.active = false;

        // Return NFT to seller
        _transfer(address(this), msg.sender, tokenId);

        emit Delisted(tokenId);
    }

    /**
     * @notice Withdraw collected platform fees (owner only)
     */
    function withdrawFees() external onlyOwner {
        uint256 amount = collectedFees;
        require(amount > 0, "No fees to withdraw");
        collectedFees = 0;
        payable(owner()).transfer(amount);
    }

    /**
     * @notice Update default fee (owner only)
     */
    function setDefaultFeeBps(uint256 newFeeBps) external onlyOwner {
        require(newFeeBps <= 1000, "Fee too high"); // Max 10%
        defaultFeeBps = newFeeBps;
    }

    // ── Required overrides ──────────────────────────────────────────────

    function tokenURI(uint256 tokenId) public view override(ERC721, ERC721URIStorage) returns (string memory) {
        return super.tokenURI(tokenId);
    }

    function supportsInterface(bytes4 interfaceId) public view override(ERC721, ERC721URIStorage) returns (bool) {
        return super.supportsInterface(interfaceId);
    }
}

contracts/PokerVRFConsumer.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

import "@chainlink/contracts/src/v0.8/vrf/dev/VRFConsumerBaseV2Plus.sol";
import "@chainlink/contracts/src/v0.8/vrf/dev/libraries/VRFV2PlusClient.sol";

/**
 * @title PokerVRFConsumer
 * @notice Requests verifiable randomness from Chainlink VRF v2.5 for poker hands
 * @dev Inherits VRFConsumerBaseV2Plus for Polygon Amoy/Mainnet
 */
contract PokerVRFConsumer is VRFConsumerBaseV2Plus {
    // VRF configuration
    uint256 public s_subscriptionId;
    bytes32 public s_keyHash;
    uint32 public s_callbackGasLimit;
    uint16 public constant REQUEST_CONFIRMATIONS = 3;
    uint32 public constant NUM_WORDS = 1;

    // Mappings
    mapping(uint256 => uint256) public requestToRandomWord;
    mapping(uint256 => bool) public requestFulfilled;
    mapping(bytes32 => uint256) public handToRequestId;

    // Events
    event RandomnessRequested(uint256 indexed requestId, string tableId, uint256 handNumber);
    event RandomnessFulfilled(uint256 indexed requestId, uint256 randomWord);

    constructor(
        address vrfCoordinator,
        uint256 subscriptionId,
        bytes32 keyHash,
        uint32 callbackGasLimit
    ) VRFConsumerBaseV2Plus(vrfCoordinator) {
        s_subscriptionId = subscriptionId;
        s_keyHash = keyHash;
        s_callbackGasLimit = callbackGasLimit;
    }

    /**
     * @notice Request randomness for a specific poker hand
     * @param tableId The table identifier
     * @param handNumber The hand number at the table
     * @return requestId The VRF request ID
     */
    function requestRandomness(
        string calldata tableId,
        uint256 handNumber
    ) external onlyOwner returns (uint256 requestId) {
        bytes32 handKey = keccak256(abi.encodePacked(tableId, handNumber));
        require(handToRequestId[handKey] == 0, "Already requested");

        requestId = s_vrfCoordinator.requestRandomWords(
            VRFV2PlusClient.RandomWordsRequest({
                keyHash: s_keyHash,
                subId: s_subscriptionId,
                requestConfirmations: REQUEST_CONFIRMATIONS,
                callbackGasLimit: s_callbackGasLimit,
                numWords: NUM_WORDS,
                extraArgs: VRFV2PlusClient._argsToBytes(
                    VRFV2PlusClient.ExtraArgsV1({nativePayment: false})
                )
            })
        );

        handToRequestId[handKey] = requestId;
        emit RandomnessRequested(requestId, tableId, handNumber);
        return requestId;
    }

    /**
     * @notice Callback from Chainlink VRF with random words
     */
    function fulfillRandomWords(
        uint256 requestId,
        uint256[] calldata randomWords
    ) internal override {
        requestToRandomWord[requestId] = randomWords[0];
        requestFulfilled[requestId] = true;
        emit RandomnessFulfilled(requestId, randomWords[0]);
    }

    /**
     * @notice Get the random word for a fulfilled request
     * @param requestId The VRF request ID
     * @return The random word (0 if not fulfilled)
     */
    function getRandomWord(uint256 requestId) external view returns (uint256) {
        return requestToRandomWord[requestId];
    }

    /**
     * @notice Update VRF configuration
     */
    function updateConfig(
        uint256 subscriptionId,
        bytes32 keyHash,
        uint32 callbackGasLimit
    ) external onlyOwner {
        s_subscriptionId = subscriptionId;
        s_keyHash = keyHash;
        s_callbackGasLimit = callbackGasLimit;
    }
}

